module deepbook::flash_loan {
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use sui::transfer;
    use sui::tx_context::{Self, TxContext};
    use deepbook::custodian_v2::{Self, Custodian, AccountCap};
    use deepbook::clob_v2::{Self, Pool};

    const EFlashLoanNotRepaid: u64 = 100;
    const EInsufficientBalance: u64 = 101;

    public fun flash_loan<DEEP>(
        pool: &mut Pool<DEEP>,
        custodian: &mut Custodian<DEEP>,
        account_cap: &AccountCap,
        amount: u64,
        ctx: &mut TxContext
    ): Coin<DEEP> {
        let deep_balance = custodian_v2::withdraw(custodian, account_cap, amount, ctx);
        coin::put(&mut pool.base_asset, deep_balance);
        coin::take(&mut pool.base_asset, amount)
    }

    public fun repay_flash_loan<DEEP>(
        pool: &mut Pool<DEEP>,
        custodian: &mut Custodian<DEEP>,
        account_cap: &AccountCap,
        loan: Coin<DEEP>,
        ctx: &mut TxContext
    ) {
        let amount = coin::value(&loan);
        coin::put(&mut pool.base_asset, loan);
        let repaid = coin::take(&mut pool.base_asset, amount);
        custodian_v2::deposit(custodian, account_cap, repaid, ctx);
    }

    public entry fun execute_flash_loan<DEEP>(
        pool: &mut Pool<DEEP>,
        custodian: &mut Custodian<DEEP>,
        account_cap: &AccountCap,
        amount: u64,
        callback: vector<u8>,
        ctx: &mut TxContext
    ) {
        let loan = flash_loan(pool, custodian, account_cap, amount, ctx);

        // Execute arbitrary callback with the loan
        sui::programmable_transaction::execute(callback, vector[loan], ctx);

        // Verify repayment
        let remaining = coin::value(&loan);
        assert!(remaining == 0, EFlashLoanNotRepaid);

        repay_flash_loan(pool, custodian, account_cap, loan, ctx);
    }
}
