module deepbook_trade::market_order {
    use sui::tx_context::{TxContext};
    use sui::coin::{Coin};
    use sui::balance::{Balance};
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::order::{Self, Order};
    use deepbook::pool::{Self, Pool};
    use deepbook::utils;
    use deepbook::math;
    use deepbook::critbit;
    use deepbook::types::{Self, Side, OrderType, OrderStatus};
    use deepbook::trade_proof::{Self, TradeProof};

    public fun execute_market_order<BaseAsset, QuoteAsset>(
        pool: &mut Pool<BaseAsset, QuoteAsset>,
        custodian: &mut CustodianV2<BaseAsset, QuoteAsset>,
        base_coin: Coin<BaseAsset>,
        quote_coin: Coin<QuoteAsset>,
        side: Side,
        quantity: u64,
        ctx: &mut TxContext
    ): (TradeProof, Coin<BaseAsset>, Coin<QuoteAsset>) {
        let (base_balance, quote_balance) = if (side == Side::Ask) {
            let base_balance = custodian_v2::deposit_base(custodian, base_coin, ctx);
            let quote_balance = custodian_v2::withdraw_quote(custodian, quote_coin, ctx);
            (base_balance, quote_balance)
        } else {
            let base_balance = custodian_v2::withdraw_base(custodian, base_coin, ctx);
            let quote_balance = custodian_v2::deposit_quote(custodian, quote_coin, ctx);
            (base_balance, quote_balance)
        };

        let order = order::new(
            side,
            OrderType::Market,
            quantity,
            0, // price not needed for market orders
            ctx
        );

        let (trade_proof, base_coin, quote_coin) = pool::execute_order(
            pool,
            order,
            base_balance,
            quote_balance,
            ctx
        );

        (trade_proof, base_coin, quote_coin)
    }

    public fun create_trade_proof<BaseAsset, QuoteAsset>(
        pool: &mut Pool<BaseAsset, QuoteAsset>,
        custodian: &mut CustodianV2<BaseAsset, QuoteAsset>,
        base_coin: Coin<BaseAsset>,
        quote_coin: Coin<QuoteAsset>,
        side: Side,
        quantity: u64,
        ctx: &mut TxContext
    ): TradeProof {
        let (trade_proof, base_coin, quote_coin) = execute_market_order(
            pool,
            custodian,
            base_coin,
            quote_coin,
            side,
            quantity,
            ctx
        );

        sui::coin::destroy_zero(base_coin);
        sui::coin::destroy_zero(quote_coin);

        trade_proof
    }
}
