    use deepbook::order::{Self, Order};
    use deepbook::pool::{Self, Pool};
    use deepbook::trade_proof::{Self, TradeProof};
    use deepbook::utils;

    public fun execute_market_order(
        pool: &mut Pool,
        custodian: &mut CustodianV2,
        base_coin: coin::Coin<SUI>,
        quote_coin: coin::Coin<SUI>,
        is_buy: bool,
        quantity: u64,
        ctx: &mut TxContext
    ): (TradeProof, coin::Coin<SUI>, coin::Coin<SUI>) {
        let (order_id, order) = order::new_market_order(
            pool,
            custodian,
            base_coin,
            quote_coin,
            is_buy,
            quantity,
            ctx
        );

        let (trade_proof, base_coin, quote_coin) = order::execute_order(
            pool,
            custodian,
            order_id,
            order,
            ctx
        );

        (trade_proof, base_coin, quote_coin)
    }

    public fun create_trade_proof(
        pool: &mut Pool,
        custodian: &mut CustodianV2,
        order_id: u64,
        order: Order,
        ctx: &mut TxContext
    ): TradeProof {
        let (trade_proof, _, _) = order::execute_order(
            pool,
            custodian,
            order_id,
            order,
            ctx
        );
        trade_proof
    }

    #[test_only]
    public fun test_market_order_execution(ctx: &mut TxContext) {
        let pool = pool::create(ctx);
        let custodian = custodian_v2::create(ctx);

        let base_coin = coin::mint_for_testing(100000000, ctx);
        let quote_coin = coin::mint_for_testing(100000000, ctx);

        let (trade_proof, base_coin, quote_coin) = execute_market_order(
            &mut pool,
            &mut custodian,
            base_coin,
            quote_coin,
            true, // is_buy
            10000, // quantity
            ctx
        );

        trade_proof::destroy(trade_proof);
        coin::destroy(base_coin);
        coin::destroy(quote_coin);
    }
}
