    use deepbook::balance_manager::{Self, BalanceManager};
    use deepbook::pool::{Self, Pool};
    use deepbook::types::{OrderSide, OrderType, OrderStatus};

    public fun place_limit_order<BaseType, QuoteType>(
        pool: &mut Pool<BaseType, QuoteType>,
        balance_manager: &mut BalanceManager,
        side: u8,
        quantity: u64,
        price: u64,
        order_type: u8,
        client_order_id: u64,
        ctx: &mut TxContext
    ) {
        let order_side = if (side == 0) OrderSide::Bid else OrderSide::Ask;
        let order_type = if (order_type == 0) OrderType::Limit else OrderType::Market;

        let balances = balances::empty();
        if (order_side == OrderSide::Bid) {
            balances::add_quote(&mut balances, math::mul(quantity, price));
        } else {
            balances::add_base(&mut balances, quantity);
        };

        balance_manager::deposit(balance_manager, balances);

        pool::place_limit_order(
            pool,
            balance_manager,
            order_side,
            quantity,
            price,
            order_type,
            client_order_id,
            ctx
        );
    }
}
