            *object::uid_to_inner(&balance_manager.id),
            side,
            order_type,
            price,
            quantity,
            clock.timestamp_ms(),
            ctx,
        );

        // Place order
        balance_manager.place_order(
            pool,
            custodian,
            order,
            base_balance,
            quote_balance,
            clock,
            ctx,
        );
    }
