module deepbook_trader::market_order {
    use sui::tx_context::{Self, TxContext};
    use sui::coin::{Self, Coin};
    use sui::balance::{Self, Balance};
    use deepbook::custodian_v2::{Self, CustodianV2};
    use deepbook::market::{Self, Market};
    use deepbook::order::{Self, Order};
    use deepbook::critbit;
    use deepbook::math;
    use deepbook::types::{Self, Side};
    use deepbook::utils;
    use deepbook::deepbook::{Self, TradeProof};

    public fun execute_market_order<BaseType, QuoteType>(
        market: &mut Market<BaseType, QuoteType>,
        custodian: &mut CustodianV2<BaseType, QuoteType>,
        quantity: u64,
        side: u8,
        base_coin: Coin<BaseType>,
        quote_coin: Coin<QuoteType>,
        ctx: &mut TxContext
    ): (TradeProof, Coin<BaseType>, Coin<QuoteType>) {
        let (base_balance, quote_balance) = if (side == (Side::Ask as u8)) {
            let base_balance = coin::into_balance(base_coin);
            let quote_balance = balance::zero();
            (base_balance, quote_balance)
        } else {
            let base_balance = balance::zero();
            let quote_balance = coin::into_balance(quote_coin);
            (base_balance, quote_balance)
        };

        let order = order::new_market_order(
            quantity,
            side,
            base_balance,
            quote_balance,
            ctx
        );

        let (trade_proof, base_balance, quote_balance) = market::execute_order(
            market,
            custodian,
            order,
            ctx
        );

        let base_coin = if (balance::value(&base_balance) > 0) {
            coin::from_balance(base_balance, ctx)
        } else {
            coin::zero(ctx)
        };

        let quote_coin = if (balance::value(&quote_balance) > 0) {
            coin::from_balance(quote_balance, ctx)
        } else {
            coin::zero(ctx)
        };

        (trade_proof, base_coin, quote_coin)
    }
}
